/// <reference path="./online-streaming-provider.d.ts" />

/**
 * Anidap provider for Seanime Denshi.
 *
 * Uses Anidap's public page metadata to resolve its internal anime slug, then
 * uses the same JSON endpoints the Anidap web player calls for episodes,
 * providers, and sources.
 */
class Provider {
  private readonly baseUrl = "https://anidap.se";
  private readonly apiBase = "https://chad.anidap.se/rest/api";
  private readonly userAgent =
    "Mozilla/5.0 (Windows NT 10.0; Win64; x64; rv:152.0) Gecko/20100101 Firefox/152.0";

  getSettings(): Settings {
    return {
      episodeServers: [
        "Auto",
        "beep",
        "mimi",
        "vee",
        "yuki",
        "loli",
        "uwu",
        "kiwi",
        "sora",
      ],
      supportsDub: true,
    };
  }

  async search(query: SearchOptions): Promise<SearchResult[]> {
    const mode: "sub" | "dub" = query.dub ? "dub" : "sub";
    const media: any = query.media || {};
    const directId = this.getAniListId(media);

    if (directId) {
      const title =
        media.englishTitle ||
        media.romajiTitle ||
        media.title?.english ||
        media.title?.romaji ||
        media.title ||
        query.query;

      const slug = await this.tryResolveSiteSlug(directId, mode);
      return [
        {
          id: this.makeSearchId(directId, slug, mode),
          title: String(title || query.query),
          url: `${this.baseUrl}/info/${directId}`,
          subOrDub: mode,
        },
      ];
    }

    const matches = await this.searchAniList(query);
    const results: SearchResult[] = [];

    for (const item of matches.slice(0, 5)) {
      const slug = await this.tryResolveSiteSlug(String(item.id), mode);
      results.push({
        id: this.makeSearchId(String(item.id), slug, mode),
        title:
          item.title?.english ||
          item.title?.romaji ||
          item.title?.native ||
          query.query,
        url: `${this.baseUrl}/info/${item.id}`,
        subOrDub: mode,
      });
    }

    return results;
  }

  async findEpisodes(providerId: string): Promise<Episode[]> {
    const parsed = this.parseId(providerId);
    const slug = parsed.slug || (await this.resolveSiteSlug(parsed.anilistId, parsed.mode));

    const episodes = await this.fetchJson<AnidapEpisode[]>(
      `${this.apiBase}/episodes?id=${encodeURIComponent(slug)}`
    );

    if (!Array.isArray(episodes)) {
      throw new Error("Anidap returned an invalid episode list");
    }

    const filtered = episodes.filter((episode) =>
      parsed.mode === "dub" ? episode.hasDub !== false : episode.hasSub !== false
    );

    return filtered
      .map((episode) => {
        const number = Number(episode.number);
        if (!Number.isFinite(number)) return null;

        return {
          id: this.makeSearchId(parsed.anilistId, slug, parsed.mode),
          number,
          title:
            episode.titles?.en ||
            episode.titles?.["x-jat"] ||
            episode.titles?.ja ||
            `Episode ${number}`,
          url: this.buildWatchUrl(parsed.anilistId, number, parsed.mode),
        } as Episode;
      })
      .filter((episode): episode is Episode => episode !== null)
      .sort((a, b) => a.number - b.number);
  }

  async findEpisodeServer(
    episode: EpisodeDetails,
    requestedServer: string
  ): Promise<EpisodeServer> {
    const parsed = this.parseId(episode.id);
    const slug = parsed.slug || (await this.resolveSiteSlug(parsed.anilistId, parsed.mode));
    const episodeNumber = Number(episode.number);

    if (!Number.isFinite(episodeNumber)) {
      throw new Error(`Invalid episode number: ${episode.number}`);
    }

    const serverInfo = await this.fetchJson<AnidapServers>(
      `${this.apiBase}/servers?id=${encodeURIComponent(slug)}` +
        `&epNum=${encodeURIComponent(String(episodeNumber))}`
    );

    const providers =
      parsed.mode === "dub"
        ? serverInfo.dubProviders || []
        : serverInfo.subProviders || [];

    const candidates = this.getProviderCandidates(
      providers,
      requestedServer,
      parsed.mode
    );
    const errors: string[] = [];

    for (const provider of candidates) {
      try {
        const sourceData = await this.fetchJson<AnidapSourceResponse>(
          `${this.apiBase}/sources?id=${encodeURIComponent(slug)}` +
            `&epNum=${encodeURIComponent(String(episodeNumber))}` +
            `&type=${encodeURIComponent(parsed.mode)}` +
            `&providerId=${encodeURIComponent(provider)}`
        );

        const subtitles = (sourceData.tracks || [])
          .filter((track) => {
            const kind = String(track.kind || "captions").toLowerCase();
            return kind === "captions" || kind === "subtitles";
          })
          .map((track, index) => ({
            id: String(track.id || `sub-${index}`),
            language: String(track.label || track.lang || "Unknown"),
            url: String(track.url || track.file || ""),
            isDefault: Boolean(track.default),
          }))
          .filter((track) => track.url.length > 0);

        const videoSources = (sourceData.sources || [])
          .map((source) => {
            const url = String(source.url || source.file || "").trim();
            if (!url) return null;

            return {
              url,
              type: this.mapSourceType(url, source.type),
              quality: String(source.quality || "auto"),
              subtitles,
            };
          })
          .filter((source): source is NonNullable<typeof source> => source !== null);

        if (!videoSources.length) {
          errors.push(`${provider}: no video sources returned`);
          continue;
        }

        return {
          server: provider,
          headers: {
            ...(sourceData.headers || {}),
            "User-Agent": this.userAgent,
          },
          videoSources,
        };
      } catch (error: any) {
        errors.push(`${provider}: ${error?.message || String(error)}`);
      }
    }

    throw new Error(
      `No playable Anidap source for episode ${episodeNumber}. ${errors.join(" | ")}`
    );
  }

  private getProviderCandidates(
    providers: AnidapProvider[],
    requestedServer: string,
    mode: "sub" | "dub"
  ): string[] {
    const available = providers.map((provider) => provider.id).filter(Boolean);
    const requested = String(requestedServer || "Auto").trim();
    const preferred = mode === "dub" ? "mimi" : "beep";
    const defaultProvider = providers.find((provider) => provider.default)?.id;
    const candidates: string[] = [];

    if (requested.toLowerCase() !== "auto" && available.includes(requested)) {
      candidates.push(requested);
    }
    if (defaultProvider) candidates.push(defaultProvider);
    if (available.includes(preferred)) candidates.push(preferred);
    candidates.push(...available);

    return candidates.filter(
      (value, index, array) => value && array.indexOf(value) === index
    );
  }

  private makeSearchId(
    anilistId: string,
    slug: string | null,
    mode: "sub" | "dub"
  ): string {
    const key = slug
      ? `${anilistId}~${encodeURIComponent(slug)}`
      : anilistId;
    return `${key}/${mode}`;
  }

  private parseId(value: string): ParsedProviderId {
    const slashIndex = value.lastIndexOf("/");
    const key = slashIndex >= 0 ? value.slice(0, slashIndex) : value;
    const rawMode = slashIndex >= 0 ? value.slice(slashIndex + 1) : "sub";
    const mode: "sub" | "dub" = rawMode === "dub" ? "dub" : "sub";
    const separatorIndex = key.indexOf("~");

    if (separatorIndex < 0) {
      return { anilistId: key, slug: null, mode };
    }

    const anilistId = key.slice(0, separatorIndex);
    const encodedSlug = key.slice(separatorIndex + 1);
    let slug = encodedSlug;

    try {
      slug = decodeURIComponent(encodedSlug);
    } catch {
      // Keep the original string if it was not URL-encoded correctly.
    }

    return { anilistId, slug: slug || null, mode };
  }

  private async tryResolveSiteSlug(
    anilistId: string,
    mode: "sub" | "dub"
  ): Promise<string | null> {
    try {
      return await this.resolveSiteSlug(anilistId, mode);
    } catch {
      return null;
    }
  }

  private async resolveSiteSlug(
    anilistId: string,
    mode: "sub" | "dub"
  ): Promise<string> {
    const html = await this.fetchText(
      this.buildWatchUrl(anilistId, 1, mode)
    );

    const deescaped = html
      .replace(/\\u002f/gi, "/")
      .replace(/\\\//g, "/")
      .replace(/&amp;/gi, "&");

    const patterns = [
      /<meta\b[^>]*property=["']og:image["'][^>]*content=["']https?:\/\/img\.anili\.st\/media\/([^"'/?#]+)["']/i,
      /<meta\b[^>]*content=["']https?:\/\/img\.anili\.st\/media\/([^"'/?#]+)["'][^>]*property=["']og:image["']/i,
      /https?:\/\/img\.anili\.st\/media\/([a-z0-9-]+)/i,
    ];

    for (const pattern of patterns) {
      const match = deescaped.match(pattern);
      if (match?.[1]) return this.decodeHtml(match[1]);
    }

    throw new Error(`Could not resolve Anidap slug for AniList ID ${anilistId}`);
  }

  private buildWatchUrl(
    anilistId: string,
    episode: number,
    mode: "sub" | "dub"
  ): string {
    const provider = mode === "dub" ? "mimi" : "beep";
    return (
      `${this.baseUrl}/watch?id=${encodeURIComponent(anilistId)}` +
      `&ep=${encodeURIComponent(String(episode))}` +
      `&type=${mode}` +
      `&provider=${provider}`
    );
  }

  private getAniListId(media: any): string | null {
    const candidates = [
      media.id,
      media.anilistId,
      media.anilistID,
      media.anilist_id,
      media.mediaId,
      media.mediaID,
    ];

    for (const candidate of candidates) {
      const value = Number(candidate);
      if (Number.isInteger(value) && value > 0) return String(value);
    }

    const urls = [media.siteUrl, media.url, media.anilistUrl];
    for (const candidate of urls) {
      const match = String(candidate || "").match(/anilist\.co\/anime\/(\d+)/i);
      if (match) return match[1];
    }

    return null;
  }

  private async searchAniList(query: SearchOptions): Promise<any[]> {
    const graphql = `
      query ($search: String, $page: Int, $perPage: Int) {
        Page(page: $page, perPage: $perPage) {
          media(search: $search, type: ANIME, sort: SEARCH_MATCH) {
            id
            format
            startDate { year month day }
            title { romaji english native }
          }
        }
      }
    `;

    const response = await fetch("https://graphql.anilist.co", {
      method: "POST",
      headers: {
        Accept: "application/json",
        "Content-Type": "application/json",
        "User-Agent": this.userAgent,
      },
      body: JSON.stringify({
        query: graphql,
        variables: { search: query.query, page: 1, perPage: 10 },
      }),
    });

    if (!response.ok) {
      throw new Error(
        `AniList search failed: ${response.status} ${response.statusText}`
      );
    }

    const data: any = await response.json();
    const items: any[] = data?.data?.Page?.media || [];
    const targetYear = query.media?.startDate?.year;
    const targetFormat = String(query.media?.format || "").toUpperCase();

    return items.sort((a, b) => {
      const score = (item: any) => {
        let value = 0;
        if (targetYear && item.startDate?.year === targetYear) value += 4;
        if (targetFormat && String(item.format || "").toUpperCase() === targetFormat) {
          value += 2;
        }
        const target = this.normalizeTitle(query.query);
        const titles = [item.title?.english, item.title?.romaji, item.title?.native]
          .filter(Boolean)
          .map((title) => this.normalizeTitle(String(title)));
        if (titles.includes(target)) value += 8;
        return value;
      };

      return score(b) - score(a);
    });
  }

  private normalizeTitle(value: string): string {
    return String(value || "")
      .toLowerCase()
      .replace(/\b(season|cour|part|uncensored)\b/g, "")
      .replace(/[^a-z0-9]+/g, "");
  }

  private async fetchJson<T>(url: string): Promise<T> {
    const response = await fetch(url, {
      headers: {
        Accept: "application/json",
        Origin: this.baseUrl,
        Referer: `${this.baseUrl}/`,
        "User-Agent": this.userAgent,
      },
    });

    if (!response.ok) {
      throw new Error(
        `Anidap API request failed: ${response.status} ${response.statusText}`
      );
    }

    return (await response.json()) as T;
  }

  private async fetchText(url: string): Promise<string> {
    const response = await fetch(url, {
      headers: {
        Accept: "text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8",
        Referer: `${this.baseUrl}/`,
        "User-Agent": this.userAgent,
      },
    });

    if (!response.ok) {
      throw new Error(
        `Anidap page request failed: ${response.status} ${response.statusText}`
      );
    }

    const html = await response.text();
    if (/just a moment|cf-chl-|cloudflare ray id/i.test(html)) {
      throw new Error("Anidap returned a Cloudflare challenge page");
    }
    return html;
  }

  private mapSourceType(url: string, rawType?: string): string {
    const type = String(rawType || "").toLowerCase();
    if (type.includes("mpegurl") || url.toLowerCase().includes(".m3u8")) {
      return "m3u8";
    }
    if (type.includes("mp4") || url.toLowerCase().includes(".mp4")) {
      return "mp4";
    }
    return type || "m3u8";
  }

  private decodeHtml(value: string): string {
    return String(value || "")
      .replace(/&amp;/gi, "&")
      .replace(/&quot;/gi, '"')
      .replace(/&#39;|&apos;/gi, "'")
      .replace(/&lt;/gi, "<")
      .replace(/&gt;/gi, ">");
  }
}

interface ParsedProviderId {
  anilistId: string;
  slug: string | null;
  mode: "sub" | "dub";
}

interface AnidapEpisode {
  number: number;
  titles?: Record<string, string>;
  hasDub?: boolean;
  hasSub?: boolean;
}

interface AnidapProvider {
  id: string;
  default?: boolean;
  tip?: string;
}

interface AnidapServers {
  subProviders?: AnidapProvider[];
  dubProviders?: AnidapProvider[];
}

interface AnidapSource {
  url?: string;
  file?: string;
  quality?: string;
  type?: string;
}

interface AnidapTrack {
  id?: string;
  url?: string;
  file?: string;
  lang?: string;
  label?: string;
  kind?: string;
  default?: boolean;
}

interface AnidapSourceResponse {
  sources?: AnidapSource[];
  tracks?: AnidapTrack[];
  headers?: Record<string, string>;
}
